INSERT INTO public.photos VALUES (22940, 'Callejâ”œâ”‚n de Nador c.1981', 'Imagen del callejâ”œâ”‚n de Nador, ascendente entre la calle de Melilla, desde donde se ha capturado la imagen, y la calle del Santuario de Nuestra Seâ”œâ–’ora de la Cabeza, en el barrio de San Josâ”œآ®. Las antiguas torrenteras y rampas naturales estâ”œأ­n en proceso de ser convertidas en escaleras mâ”œأ­s accesibles. Un ciudadano inspecciona las obras. Tras el posterior derribo de las parcelas en ruinas a sus espaldas (arriba, recayentes a la plaza del Diez de Agosto), todo este espacio quedarâ”œأ­ unificado bajo la denominaciâ”œâ”‚n de calle del 10 de Agosto, homenaje en el nomenclâ”œأ­tor al fracasado intento de golpe de Estado de Sanjurjo en 1932, que tras la recuperaciâ”œâ”‚n de la democracia ha sobrevivido a once legislaturas estatales, y nueve municipales Parece ser que a la dâ”œآ®cima va a ir la vencida. Fuente visual: AVV. de San Josâ”œآ®.', 1981, 1981, 1981, 'Anos 80', 'SAN JOSâ”œأ«', 41.63275700, -0.87712500, '0101000020E6100000C520B0726811ECBF54A86E2EFED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33149770584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33149770584.webp', 'https://www.flickr.com/photos/zaragozaantigua/33149770584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23150, 'Travesâ”œآ،a Puente Virrey 2000', 'Imagen que captura, desde cierta altura, la finalizaciâ”œâ”‚n del derribo de las antiguas parcelas comprendidas entre el nâ”œâ•‘mero 30 (cuya impronta perdura en el vecino bloque, como si de un corte estratigrâ”œأ­fico se tratara), y el 52 de la travesâ”œآ،a del Puente del Virrey, derribo impulsado por una destacada empresa constructora con un peso mâ”œأ­s que apreciable en el urbanismo del barrio de San Josâ”œآ®. Tras el derribo, el proyecto incluâ”œآ،a la apertura de un nuevo vial que diera a la calle del Tejar una continuidad mâ”œأ­s espaciosa para el trâ”œأ­fico rodado. Esta calle serâ”œآ،a luego denominada Miguel â”œأ¼ngel Tricas de Pablo, como homenaje a su trabajo desde la asociaciâ”œâ”‚n de vecinos del barrio. A ambos lados de la calle se habrâ”œآ،an de levantar dos grandes bloques de viviendas, denominado el uno "Edificio Virrey I", terminado hace aâ”œâ–’os y ya habitado, y el "Edificio Virrey II", que sigue en barbecho, o limbo constructivo. Las medianeras de la imagen se corresponden con el Grupo de Viviendas Puente Virrey y calle Tejar, promovido a principios de los aâ”œâ–’os 50 para trabajadores de la fâ”œأ­brica textil de Pina. En esa zona, precisamente, se localiza el terminado "Edificio Virrey I", que ha cegado la visual de las irregulares ventanas abiertas en la medianera.', 2000, 2000, 2000, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.63553400, -0.87606100, '0101000020E610000040A20914B108ECBF7FBF982D59D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32195531145.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32195531145.webp', 'https://www.flickr.com/photos/zaragozaantigua/32195531145/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23170, 'Av. de San Josâ”œآ® 2004', 'Imagen capturada desde cierta altura (posiblemente, el nâ”¬â•‘ 95 de la avenida de Tenor Fleta), del tramo mâ”œأ­s alto de la avenida de San Josâ”œآ®, entre Tenor Fleta y la Vâ”œآ،a de San Fernando (al fondo), tras la remodelaciâ”œâ”‚n acometida en la segunda mitad de ese aâ”œâ–’o. Casi en el centro de la imagen, donde la parada de autobuses urbanos, vista parcial de las ruinas de la antigua manzana de parcelas entre las calles de Bellavista, avenida de San Josâ”œآ®, y travesâ”œآ،a del Puente del Virrey. Una parte de ese solar, urbanizado y convertido en plaza pâ”œâ•‘blica, recibiâ”œâ”‚ recientemente la denominaciâ”œâ”‚n de plaza del 1â”¬â•‘ de mayo, nomenclâ”œأ­tor que fue erradicado del barrio de San Josâ”œآ® tras el 18 de julio de 1936. Casi al fondo de la avenida, a la izquierda, se recorta todavâ”œآ،a la alta silueta del silo de la harinera de Pellicer Industria Panificadora S.A. (PEIPASA), cerrada pocos aâ”œâ–’os antes. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 2004, 2004, 2004, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.63705700, -0.87768100, '0101000020E61000002942EA76F615ECBF0C5872158BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33085321183.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33085321183.webp', 'https://www.flickr.com/photos/zaragozaantigua/33085321183/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24060, 'Recinto ferial 1973', 'Desde la avenida del Tenor Fleta, vista en altura del espacio donde se montaban las ferias de las Fiestas del Pilar durante los primeros aâ”œâ–’os 70. A la izquierda, muros perimetrales del colegio de los Agustinos. A la derecha, el colegio pâ”œâ•‘blico de San Josâ”œآ® de Calasanz. Al fondo, restos de la huerta de Miraflores, prolongaciâ”œâ”‚n del paseo de Marina Moreno, y traseras edilicias de las calles de la Licorera, Fueros del Trabajo y de Manuel Lorenzo Pardo.', 1973, 1973, 1973, 'Anos 70', 'SAN JOSâ”œأ«', 41.64105900, -0.87908600, '0101000020E6100000F8E28BF67821ECBF3AE7A7380ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32215214696.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32215214696.webp', 'https://www.flickr.com/photos/zaragozaantigua/32215214696/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22256, 'Universidad 1962', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/1962. Objetivamente, en la jerarquâ”œآ،a moral de muchos seres humanos el burro, o asno, es considerado terco, necio e insensible, y ocupa un muy bajo estrato de consideraciâ”œâ”‚n. Por ello, en escenarios festivos varios, organizan "carreras de burros" que les dan muchas risas y divertimentos, pues los burros acostumbran a negarse a avanzar hacia lo que presumen desagradable, o simplemente estâ”œâ•‘pido. Porque, los burros, como otras muchas especies animales, no suelen ser competitivos, y el concepto de "correr" para "ganar" les resulta inconcebible, es algo que sâ”œâ”‚lo estâ”œأ­ en el ideario de quienes les montan. Aâ”œâ•‘n perdura esta prâ”œأ­ctica, que la imagen recoge practicada, precisamente, en el entonces reciente campus universitario de la Plaza de San Francisco. Al fondo, la Facultad de Ciencias. A la izquierda, la de Derecho.', 1962, 1962, 1962, 'Anos 60', 'UNIVERSIDAD', 41.64120000, -0.89893600, '0101000020E6100000484E266E15C4ECBFFC1873D712D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14665208717.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14665208717.webp', 'https://www.flickr.com/photos/zaragozaantigua/14665208717/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24112, 'C.â”¬â•‘ de San Josâ”œآ® 1942', 'Imagen capturada durante el fresco mediodâ”œآ،a del lunes 16 de febrero de 1942 con motivo de la inauguraciâ”œâ”‚n oficial de la Comisarâ”œآ،a de San Josâ”œآ® sita en el homâ”œâ”‚nimo camino, en el tramo de los pares entre el camino que por los campos de Miraflores conduce al camino de Las Torres, y la calle del Padre Polanco. Centra la escena el reverendo padre Luis Doâ”œâ–’ate, regente de la parroquia de San Miguel de los Navarros que preceptivamente bendijo los nuevos locales. Junto a â”œآ®l y a la izquierda, el secretario general del jefe superior de Policâ”œآ،a, Enrique Fontana Bernabâ”œآ®u, que inaugurâ”œâ”‚ la comisarâ”œآ،a terminando con los no menos preceptivos gritos de "viva Franco" y "Arriba Espaâ”œâ–’a", y el comandante en jefe de la policâ”œآ،a armada y de trâ”œأ­fico, Josâ”œآ® Arija Valenzuela. Junto a â”œآ®l y a la derecha, el inspector jefe de la brigada de investigaciâ”œâ”‚n criminal, Ismael Bas Ballester. Posan junto a ellos, ademâ”œأ­s, funcionarios del Cuerpo de policâ”œآ،a adscritos a esta nueva comisarâ”œآ،a (con un total de cinco inspectores y nueve agentes, ademâ”œأ­s del comisario jefe Josâ”œآ® Abello Drets), cuya jurisdicciâ”œâ”‚n quedâ”œâ”‚ delimitada al este de la lâ”œآ،nea imaginaria que desde el puente del Pilar, pasando por la calle del Heroâ”œآ،smo, camino de las Torres, paseos de Cuâ”œآ®llar y de Colâ”œâ”‚n, llegaba hasta el parque de Buenavista. Sobre el posado grupal se proyecta la leve sombra de algunas desnudas ramas de los â”œأ­rboles que jalonaban el camino de San Josâ”œآ® hasta que poco despuâ”œآ®s fueron cortados para dar paso al tendido tranviario de la nueva lâ”œآ،nea 13 "San Josâ”œآ®" inaugurada en 1945.', 1942, 1942, 1942, 'Anos 40', 'SAN JOSâ”œأ«', 41.63963700, -0.87456100, '0101000020E6100000016DAB5967FCEBBFE1270EA0DFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52039019692.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52039019692.webp', 'https://www.flickr.com/photos/zaragozaantigua/52039019692/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24205, 'Tenor Fleta 1968', 'Imagen capturada durante el proceso de urbanizaciâ”œâ”‚n de la avenida del Tenor Fleta, como una toma de contacto con el estado previo, a la altura del arranque de la calle de Lausana, a la derecha. El objetivo se centra en una chimenea construida por RENFE tras el soterramiento de las vâ”œآ،as, como vâ”œآ،a de salida de los humos generados por las locomotoras vaporosas de la lâ”œآ،nea de Barcelona. En primer plano, y adoquinada, la antigua calle de Fletas. Fuente visual: Archivo Municipal de Zaragoza.', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”œأ«', 41.63866900, -0.87916200, '0101000020E6100000B859BC581822ECBF09FCE1E7BFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32812602593.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32812602593.webp', 'https://www.flickr.com/photos/zaragozaantigua/32812602593/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24471, 'Chimenea de Pina 1984', 'Imagen de la identificativa, reivindicada y derribada chimenea de la antigua fâ”œأ­brica textil de Pina y Marâ”œآ،n, cuando era reclamada por el movimiento vecinal organizado como parte de un nuevo parque. Esta chimenea, recuerdo de tiempos fabriles, era reivindicada como parte de la memoria visual de ese pasado, y se le asignaba un carâ”œأ­cter central en el proyecto de parque propuesto. Hasta que una maâ”œâ–’ana, la chimenea ya no estaba: el Ayuntamiento la derribâ”œâ”‚ con alevosâ”œآ،a y nocturnidad. El proyecto del Jardâ”œآ،n de la Memoria fue tambiâ”œآ®n un adelantado a su tiempo en este sentido: unos aâ”œâ–’os despuâ”œآ®s las chimeneas ya no eran consideradas enemigas del Progreso, y la tendencia fue mâ”œأ­s conservacionista. O tempora, o mores. Al fondo de la imagen, a la izquierda, la gigantesca y singular urbanizaciâ”œâ”‚n de la calle Pintor Marâ”œآ،n Bagâ”œâ•‌â”œآ®s. Fuente visual: AVV. San Josâ”œآ®', 1984, 1984, 1984, 'Anos 80', 'SAN JOSâ”œأ«', 41.63409600, -0.87890600, '0101000020E6100000FA42C879FF1FECBF2043C70E2AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20345608126.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20345608126.webp', 'https://www.flickr.com/photos/zaragozaantigua/20345608126/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25722, 'Escultor Lobato 1968', 'Imagen del camino del Escultor Lobato tal y como era entonces, con las antiguas parcelas, las empinadas cuestas, el camino de tierra, la acequia, y algunas farolas. Al fondo, la calle Garcâ”œآ،a Lorca, y mâ”œأ­s al fondo, la avenida de San Josâ”œآ®. Cruza descendente (o ascendente, segâ”œâ•‘n donde se vaya) la reciente y tambiâ”œآ®n terrosa calle Joaquâ”œآ،n Sorolla, junto a la antigua fâ”œأ­brica de Pina, desde la calle de Cantarranas (arriba), hasta la del Doce de Octubre (abajo). Fuente: "Zaragoza viva" (1969)', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”œأ«', 41.63430500, -0.87797200, '0101000020E610000002B859BC5818ECBF3A58FFE730D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19923307013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19923307013.webp', 'https://www.flickr.com/photos/zaragozaantigua/19923307013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25725, 'Calixto Ariâ”œâ–’o 1976', 'Hacâ”œآ،a meses que la "Asociaciâ”œâ”‚n de Padres de Alumnos" (sic) del Colegio "Calixto Ariâ”œâ–’o y Mariano de Cavia", y la Asociaciâ”œâ”‚n de Cabezas de Familia de S. Josâ”œآ® llevaban denunciando la penosa situaciâ”œâ”‚n del colegio "Nacional" (sic), y planteando su sustituciâ”œâ”‚n por uno nuevo. El 16 de noviembre, el Alcalde, Sr. Merino, recibiâ”œâ”‚ a una representaciâ”œâ”‚n de ambas entidades, y allâ”œآ، saliâ”œâ”‚ la posibilidad de permutar terrenos con los de la DPZ en "La Granja" para construir allâ”œآ، unas nuevas escuelas. El Colegio "Calixto Ariâ”œâ–’o y Mariano de Cavia" habâ”œآ،a sido edificado en 1931, cuando la Segunda Repâ”œâ•‘blica impulsâ”œâ”‚ la construcciâ”œâ”‚n urgente de escuelas (habâ”œآ،a un dâ”œآ®ficit de mâ”œأ­s de 27000 escuelas, y mâ”œأ­s de un millâ”œâ”‚n de niâ”œâ–’os y niâ”œâ–’as estaban sin escolarizar). Tenâ”œآ،a capacidad para 400 niâ”œâ–’as y niâ”œâ–’os, en condiciones que hay que recordar: la luz elâ”œآ®ctrica tenâ”œآ،a que estar siempre encendida porque las aulas eran oscuras, sombrâ”œآ،as; los muros rezumaban humedad; el patio apenas contaba con 40 m2; el paso de los aâ”œâ–’os habâ”œآ،a degradado la construcciâ”œâ”‚n, realizada en materiales sencillos; los baâ”œâ–’os goteaban fuerte... Eran tiempos en que 6000 niâ”œâ–’as y niâ”œâ–’as del barrio tenâ”œآ،an que irse a otros barrios, o morir al palo de los colegios privados y confesionales, para poder escolarizarse. En la imagen, el Colegio visto desde el cruce de Tenor Fleta con el Camino del Puente del Virrey. El patio, con los dos â”œأ­rboles, quedaba en medio de los dos pabellones, uno para niâ”œâ–’as, y otro para niâ”œâ–’os. La entrada al Colegio estaba por detrâ”œأ­s de la imagen, en la Calle Dos de Mayo. Fuente visual: Archivo Heraldo de Aragâ”œâ”‚n.', 1976, 1976, 1976, 'Anos 70', 'SAN JOSâ”œأ«', 41.63638900, -0.87500000, '0101000020E6100000000000000000ECBF5F44DB3175D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20064377628.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20064377628.webp', 'https://www.flickr.com/photos/zaragozaantigua/20064377628/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25731, 'Callejâ”œâ”‚n de Nador 1977', 'Muy cerca ya del Canal Imperial las cuestas y empinamientos casi comienzan a parecer cordilleras a los llaneros de la ciudad romana. Tal vez por eso, desde antiguo, se consideraba natural que el monte de Torrero comenzara ya donde la actual Doce de Octubre. El Cabezo Cortado, un poco mâ”œأ­s arriba, era el Olimpo de la periferia, al que venâ”œآ،an artistas y fotâ”œâ”‚grafos cuando querâ”œآ،an "retratar" bien la ciudad. No obstante los desniveles, la progresiva afluencia de gente del campo a la ciudad empujâ”œâ”‚ a construir donde no parece posible hacerlo. Pero aquâ”œآ، el precio del suelo estaba por los idems, los materiales de construcciâ”œâ”‚n se abastecâ”œآ،an allâ”œآ، mismo (adobe, ladrillo, maderos, teja), y la mano de obra salâ”œآ،a de la familia y amistades. Asâ”œآ،, los antiguos caminos y calles de Alcalâ”œأ­ Zamora, Mâ”œأ­rtires de Jaca, 14 de abril, de la Huerta, y del 14 de diciembre, fueron poblâ”œأ­ndose de prodigiosas construcciones, humildes (proletarias, en lenguaje antiguo). Los riegos fluâ”œآ،an de la cercana acequia de Ontanar, y en los terraplenes entre la calle Melilla y Escultor Lobato crecâ”œآ،a maâ”œآ،z y cereal. Cuando llovâ”œآ،a, torrentes y barranqueras surgâ”œآ،an donde antes sâ”œâ”‚lo habâ”œآ،a polvo, niebla, viento, y sol. En la imagen, aspecto del confuso espacio ascendente del callejâ”œâ”‚n de Nador, a la izquierda, o lado de los nâ”œâ•‘meros pares. Tras las parcelas del centro de la imagen, arriba, estaba la plaza del Diez de Agosto, y a la derecha, una calle homâ”œâ”‚nima, de una fecha que recuerda la derogaciâ”œâ”‚n en 1792 de la monarquâ”œآ،a durante la Revoluciâ”œâ”‚n Francesa, aunque oficialmente es un homenaje al fracasado intento de Golpe de Estado de Sanjurjo en 1932. Mâ”œأ­s tarde, y tras el derribo de las parcelas referidas, todo este espacio fue adjudicado a la denominaciâ”œâ”‚n de calle del Diez de Agosto. El edificio de la derecha es el nâ”¬â•‘ 6-8 de la calle de Nuestra Seâ”œâ–’ora de la Cabeza. Los edificios de arriba a la izquierda perduran como nâ”¬â•‘ 4 y nâ”¬â•‘ 6 de la calle Diez de Agosto. El resto de parcelas, supervivientes de la construidas durante los', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”œأ«', 41.63275700, -0.87712500, '0101000020E6100000C520B0726811ECBF54A86E2EFED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20204876386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20204876386.webp', 'https://www.flickr.com/photos/zaragozaantigua/20204876386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25746, 'Ex-Calixto Ariâ”œâ–’o 1988', 'Las antiguas "Escuelas de Calixto Ariâ”œâ–’o-Mariano de Cavia", luego Colegio Nacional "Calixto Ariâ”œâ–’o" estaba domiciliado en la calle Dos de Mayo nâ”¬â•‘ 35. Por Orden de 28 de agosto de 1979, de la Direcciâ”œâ”‚n General de Educaciâ”œâ”‚n Bâ”œأ­sica, fue trasladado a "locales de nueva construcciâ”œâ”‚n en calle Josâ”œآ® Galisay, sin nâ”œâ•‘mero, (barrio San Josâ”œآ®-La Granja)" (sic). Tras el traslado quedâ”œâ”‚ abandonado, pasando por un tiempos muy complicados cuando su cesiâ”œâ”‚n temporal, y en precario, a la comunidad gitana. Finalmente, fue derribado, y en la segunda mitad de los 90 fue objeto de una promociâ”œâ”‚n de viviendas denominada "Calixto Ariâ”œâ–’o" que comenzâ”œâ”‚ las obras en 1996, con 38 viviendas, locales, aparcamientos y trasteros. Fuente visual: AVV. San Josâ”œآ®.', 1988, 1988, 1988, 'Anos 80', 'SAN JOSâ”œأ«', 41.63638900, -0.87500000, '0101000020E6100000000000000000ECBF5F44DB3175D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20388991672.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20388991672.webp', 'https://www.flickr.com/photos/zaragozaantigua/20388991672/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25758, 'Avenida de San Josâ”œآ® 1950', 'El "Diamante Negro", en la avenida de San Josâ”œآ®, es el antecedente directo del mâ”œآ،tico Bar-Restaurante Fujiyama (nâ”¬â•‘ 137 de la avenida). El singular nombre vendrâ”œآ،a dado por la traducciâ”œâ”‚n poâ”œآ®tica del habitual uso del local como depâ”œâ”‚sito de carbâ”œâ”‚n (carbonera), ademâ”œأ­s de otros productos antiguos, como la paja. Una vez despejado y limpio de carbâ”œâ”‚n y paja, fue habilitado como "Salâ”œâ”‚n (de baile) de la Comisiâ”œâ”‚n" durante las fiestas del barrio de San Josâ”œآ®. Tenâ”œآ،a como vecina una notoria vaquerâ”œآ،a, pero el ingenio y una ocurrente decoraciâ”œâ”‚n con coloristas motivos florales y guirnaldas varias, convirtiâ”œâ”‚ el espacio en otra cosa. Por aâ”œâ–’adidura, el soleado posado de unas endomingadas mozas a la puerta del local, parece un reclamo de fiesta y baile, con un ambiente muy similar al de decenas y decenas de pueblos (eso eran entonces los barrios de la periferia de la ciudad) en sus fiestas mayores. En la imagen, acceso desde la avenida de San Josâ”œآ® al festivo y resplandeciente local. Fuente visual: Banco de Imâ”œأ­genes del Barrio de S. Josâ”œآ® (A.VV. San Josâ”œآ®)', 1950, 1950, 1950, 'Anos 50', 'SAN JOSâ”œأ«', 41.63792300, -0.87629700, '0101000020E610000037A79201A00AECBFE02EFB75A7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24153781489.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24153781489.webp', 'https://www.flickr.com/photos/zaragozaantigua/24153781489/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25767, 'Cadena de la Granja 1977', 'Imagen capturada seguramente por la singularidad del galguero que, ascendiendo por la calle Cadena de la Granja (que conducâ”œآ،a a la antigua Granja Agrâ”œآ،cola de Zaragoza), ha llegado al cruce con el camino del Puente del Virrey, donde finaliza la avenida de Tenor Fleta, y la circulaciâ”œâ”‚n rodada gira 45â”¬â•‘ hacia nuestra derecha para continuar ruta. A la izquierda, de fondo, destacable imagen de las antiguas Escuelas de Calixto Ariâ”œâ–’o y Mariano de Cavia, con entrada por la recayente calle del Dos de Mayo (antigua del 1â”¬â•‘ de mayo). Justo a la izquierda, tambiâ”œآ®n, aunque fuera de plano, finalizaba el soterramiento de la lâ”œآ،nea ferroviaria. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”œأ«', 41.63642200, -0.87450700, '0101000020E610000035F0A31AF6FBEBBF3B3AAE4676D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33039710135.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33039710135.webp', 'https://www.flickr.com/photos/zaragozaantigua/33039710135/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25769, 'Tenor Fleta 1968', 'Imagen del tramo final de la moderna avenida del Tenor Fleta, entre la avenida de San Josâ”œآ® (a la espalda), y el camino del Puente del Virrey (al fondo), al que afortunadamente nadie proponâ”œآ،a cambiar la denominaciâ”œâ”‚n de "camino" (â”¬â”گreminiscencia rural?) por la de "avenida" (â”¬â”گmâ”œأ­s propio de una ciudad moderna?). Parece ser que la urbanizaciâ”œâ”‚n de este vial se estaba encontrando con problemas como el de la imagen: los modernos bloques, en su avance, como el nâ”¬â•‘ 120, topan con una parcela recayente a la calle del Dos de Mayo (antigua del 1â”¬آ¬ de Mayo) que conserva el alineamiento original de los jardines y huertos traseros. Tras ella, las escuelas de Calixto Ariâ”œâ–’o y Mariano de Cavia, aunque algo mâ”œأ­s retranqueadas, tampoco habâ”œآ،an previsto la nueva alineaciâ”œâ”‚n. Al poco tiempo, la parcela irredenta fue sustituida por un moderno bloque (nâ”¬â•‘ 122) alineado ortodoxamente, y la acera resultante fue adaptada de forma plâ”œأ­stica a unos pocos centâ”œآ،metros junto a las escuelas donde hacer equilibrios impensables. Tendrâ”œآ،an que pasar unos cuantos aâ”œâ–’os para que el derribo del Calixto Ariâ”œâ–’o normalizara la situaciâ”œâ”‚n. Al fondo, naves industriales en la calle Cadena de la Granja, junto a las vâ”œآ،as del tren. La imagen presenta un aire de irrealidad: no hay circulaciâ”œâ”‚n rodada. Fuente visual: foto AMZ.', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”œأ«', 41.63676000, -0.87560000, '0101000020E61000004D158C4AEA04ECBF53B3075A81D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33184504891.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33184504891.webp', 'https://www.flickr.com/photos/zaragozaantigua/33184504891/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25771, 'C.â”¬â•‘ del Puente del Virrey 1976', 'Antropolâ”œâ”‚gica imagen capturada en la confluencia del antiquâ”œآ،simo camino del Puente del Virrey (derecha), con la mâ”œأ­s moderna travesâ”œآ،a del Puente del Virrey (izquierda), por donde todavâ”œآ،a bajaba al aire la acequia del Plano en su trâ”œأ­nsito hacia el camino de Miraflores, y un desmadejado, pero estratâ”œآ®gico, â”œأ­rbol (posiblemente, una acacia) generaba un microespacio de convivencia intergeneracional, y de sombra en verano, ciertamente impagable. Cosas de barrio de la periferia (San Josâ”œآ®). Fuente visual: foto Calvo Pedrâ”œâ”‚s, en diario "El Noticiero". Archivo Josâ”œآ® Marâ”œآ،a Ballestâ”œآ،n Miguel.', 1976, 1976, 1976, 'Anos 70', 'SAN JOSâ”œأ«', 41.63508200, -0.87529000, '0101000020E6100000C381902C6002ECBF9E23F25D4AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33304604076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33304604076.webp', 'https://www.flickr.com/photos/zaragozaantigua/33304604076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25772, 'Tenor Fleta 1968', 'Imagen capturada durante el proceso de urbanizaciâ”œâ”‚n de la avenida del Tenor Fleta, en este caso en un corto tramo entre el cruce con la avenida de San Josâ”œآ® (derecha), y el bloque del nâ”¬â•‘ 94, en el centro. A su derecha, restos de las parcelas nâ”¬â•‘ 90, y 92, donde poco despuâ”œآ®s, tras ser retranqueadas, serâ”œآ،a construido un nuevo bloque con ese numeral. A su derecha, cartelones comerciales apoyados en el antiguo nâ”¬â•‘ 145 de la avenida de San Josâ”œآ®. Al otro lado de la avenida, la guarderâ”œآ،a أ”أ‡آ£Santa Marâ”œآ،a del Pilarأ”أ‡أک, y los novâ”œآ،simos y grandes bloques construidos por una entidad de ahorro local. El trâ”œأ­fico rodado, el usual de la â”œآ®poca, en nâ”œâ•‘mero, y calidades. Fuente visual: Archivo Municipal de Zaragoza.', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”œأ«', 41.63733800, -0.87683400, '0101000020E6100000EBAA402D060FECBFC03FA54A94D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33473240482.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33473240482.webp', 'https://www.flickr.com/photos/zaragozaantigua/33473240482/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25774, 'Calle del Dos de Mayo 1967', 'Imagen de la calle del Dos de Mayo, centrada en el primer tramo del lado de los pares, con una interesante panorâ”œأ­mica de la transiciâ”œâ”‚n del original estado parcelario, a nuevos bloques levantados sobre sus solares. Asâ”œآ،, en el centro de la imagen, se muestra en construcciâ”œâ”‚n el nuevo edificio del nâ”¬â•‘ 14-16, resultado de la fusiâ”œâ”‚n solariega de las antiguas parcelas 14 y 16. A su derecha, las parcelas 12, 10 y 8, que mâ”œأ­s tarde serâ”œأ­n refundidas en un nuevo bloque unitario. A su izquierda, las antiguas parcelas 18, 20 y 22, luego sustituidas por otro bloque moderno, y vista parcial de la parcela 24, incorporada luego a otro mâ”œأ­s moderno y vertical bloque. Al fondo, el arranque de la calle desde la avenida de San Josâ”œآ®, con las parcelas 6, 4 y 2, ya modernizadas. Si bien en la imagen el bloque en construcciâ”œâ”‚n parece destacar bastante del entorno, no deja de ser una modesto edificio de apenas cuatro alturas, mâ”œأ­s bajos, aunque aprovechando de forma mâ”œأ­s â”œâ”‚ptima la edificabilidad de los antiguos y abiertos patios y corrales de las traseras. La denominaciâ”œâ”‚n de esta calle (Dos de Mayo) fue impuesta tras el 18 de julio de 1936 sobre la anterior del 1â”¬â•‘ de Mayo, como una mâ”œأ­s de las numerosas referencias urbanas relacionadas con la memoria histâ”œâ”‚rica de las guerras peninsulares de 1808-14. Fuente visual: colecciâ”œâ”‚n de Enrique Baile, en Gran Archivo Zaragoza Antigua (GAZA).', 1967, 1967, 1967, 'Anos 60', 'SAN JOSâ”œأ«', 41.63692100, -0.87651200, '0101000020E610000050A6D1E4620CECBF5C9198A086D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33867495386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33867495386.webp', 'https://www.flickr.com/photos/zaragozaantigua/33867495386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25778, 'Av. de San Josâ”œآ® 1945', 'Imagen capturada el 30 de agosto de 1945 con motivo de la inauguraciâ”œâ”‚n de la tranviaria lâ”œآ،nea 13 "San Josâ”œآ®", trazada con vâ”œآ،a doble por la avenida de San Josâ”œآ® (una de subida, otra de bajada). Para habilitar el espacio necesario para instalar el tendido se hubieron de talar los â”œأ­rboles que jalonaban el antiguo camino, y la penuria de materiales que caracterizâ”œâ”‚ la Autarquâ”œآ،a franquista hizo que los materiales en buena parte tuvieran que ser reutilizados de la desmantelada lâ”œآ،nea de Circunvalaciâ”œâ”‚n, y de algunos tramos de otras lâ”œآ،neas. La terminal de salida estaba ubicada en la calle de la Verâ”œâ”‚nica (en las traseras del Teatro Principal), pasando luego por el Coso, la calle de Espartero, la plaza de San Miguel, la calle de Miguel Servet, el cuartel de Intendencia, y la avenida de San Josâ”œآ®, por la que ascendâ”œآ،a hasta justo donde comenzaba lo mâ”œأ­s duro de la cuesta de Morâ”œâ”‚n, en las inmediaciones de la harinera homâ”œâ”‚nima, desde donde regresaba al centro de la ciudad. En la imagen, el coche nâ”¬â•‘ 92 asciende por la avenida posiblemente en el despejado tramo entre la calle de Fletas, donde la trinchera del ferrocarril de los directos a Barcelona, y el arranque del camino de las Alcachoferas. A la derecha, fuera de plano, parcelas junto a los ingresos a la calle del Dos de Mayo y a la de Ventura Rodrâ”œآ،guez. Fuente visual: Foto Lozano en El Noticiero, del archivo de Josâ”œآ® Marâ”œآ،a Ballestâ”œآ،n Miguel.', 1945, 1945, 1945, 'Anos 40', 'SAN JOSâ”œأ«', 41.63705700, -0.87768100, '0101000020E61000002942EA76F615ECBF0C5872158BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40007125933.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40007125933.webp', 'https://www.flickr.com/photos/zaragozaantigua/40007125933/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25780, 'Calle del Dos de Mayo 1966', 'Matinal y soleada imagen de la calle del Dos de Mayo (antigua avenida del 1.â”¬â•‘ de Mayo) con una vista parcial centrada en las antiguas parcelas de los nâ”œâ•‘meros 14 y 16 poco antes de su derribo para ser sustituidas por un moderno bloque de viviendas. A la izquierda la parcela del 18, y a la derecha la parcela del 12. Ambas tambiâ”œآ®n serâ”œأ­n luego derribadas e integradas en sendos nuevos bloques edilicios. Al fondo, luminosas traseras del nuevo bloque de los nâ”œâ•‘meros 5-7-9 de la calle de Ventura Rodrâ”œآ،guez, antigua de la Igualdad. De la treintena de parcelas que fueron levantadas en este largo vial, con viviendas unifamiliares de una y dos alturas, apenas sobrevive a fecha de hoy una, la nâ”¬â•‘ 30. Fuente visual: colecciâ”œâ”‚n de Enrique Baile, en Gran Archivo Zaragoza Antigua (GAZA).', 1966, 1966, 1966, 'Anos 60', 'SAN JOSâ”œأ«', 41.63692100, -0.87651200, '0101000020E610000050A6D1E4620CECBF5C9198A086D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40723561224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40723561224.webp', 'https://www.flickr.com/photos/zaragozaantigua/40723561224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25782, 'Av. de San Josâ”œآ® c.1967', 'Tranviaria imagen centrada en el coche nâ”¬â•‘ 305 (serie de los "300") en servicio en la nueva lâ”œآ،nea "Parque-San Josâ”œآ®", resultado de la unificaciâ”œâ”‚n de las lâ”œآ،neas 11 y 13, estacionado en la terminal sita en la avenida de San Josâ”œآ®, tramo entre las calles de Bellavista (parcela a la izquierda) y la del Doce de Octubre (a la derecha, fuera de plano). Se encuentra orientado para comenzar el viaje de vuelta hacia la terminal del Teatro Principal. De fondo, edificio junto a la fâ”œأ­brica de La Catedral del Mueble que un incendio se llevâ”œâ”‚ luego por delante. Desde entonces aquâ”œآ، se encuentran los verticales y modernos inmuebles del 167-169 de la avenida. Fuente visual: Archivo de Josâ”œآ® Marâ”œآ،a Ballestâ”œآ،n Miguel.', 1967, 1967, 1967, 'Anos 60', 'SAN JOSâ”œأ«', 41.63607700, -0.87874500, '0101000020E6100000ADC090D5AD1EECBF705E9CF86AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41164628952.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41164628952.webp', 'https://www.flickr.com/photos/zaragozaantigua/41164628952/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25788, 'Calle de la Igualdad 1927', 'Imagen del tramo final de la terrosa calle de la Igualdad del barrio de San Josâ”œآ® capturada desde su desemboque en el camino del Puente del Virrey. Parcelas de una y dos alturas (las menos) jalonan esta calle, donde a la derecha destaca el pequeâ”œâ–’o riego que bajaba al aire por todo el vial desde su arranque al fondo, en el camino de San Josâ”œآ®, donde destacan algunos de sus veteranos olmos que se superponen a los â”œأ­rboles de la torre de Fletas. Tras las parcelas de la izquierda bajaba tambiâ”œآ®n muy caudalosa la acequia del Plano por la travesâ”œآ،a del Puente del Virrey. A pesar de que esta calle presentaba su nombre de "Igualdad" desde el comienzo de la dictadura del general Primo de Rivera, tras el 18 de julio de 1936 fue renombrada con el "menos problemâ”œأ­tico" de Ventura Rodrâ”œآ،guez, lo que para ser una barriada de la periferia, fue todo un honor... Lo mismo le sucediâ”œâ”‚ a su paralela e inmediata calle del 1â”¬آ¬ de Mayo (a la derecha y fuera de plano), que desde entonces es la calle del Dos de Mayo.', 1927, 1927, 1927, 'Anos 20', 'SAN JOSâ”œأ«', 41.63572400, -0.87516100, '0101000020E61000004D8237A45101ECBF23A46E675FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52197487621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52197487621.webp', 'https://www.flickr.com/photos/zaragozaantigua/52197487621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25793, 'Plaza de las Terrazas 1925', 'Fotograma de un reportaje dedicado a la "garden party" organizada en honor de los asistentes al I Congreso de "Oto-Rino-Laringologâ”œآ،a" celebrado en Zaragoza en abril de ese aâ”œâ–’o y en cuyo marco fue constituida la "Asociaciâ”œâ”‚n Hispano-Lusa-Americana" de esta especialidad mâ”œآ®dico-quirâ”œâ•‘rgica. El espacio elegido para esta celebraciâ”œâ”‚n fueron los "pintorescos" y singulares jardines de la torre de Dâ”œأ­maso Pina Pâ”œآ®rez sita al final de la playa de Torrero, y ademâ”œأ­s de los congresistas asistieron "las mâ”œأ­s distinguidas familias de la buena sociedad zaragozana". Hubo orquesta, jotas y un "exquisito lunch" cuyos caldos elevaron el tono del evento.', 1925, 1925, 1925, 'Anos 20', 'SAN JOSâ”œأ«', 41.63285300, -0.87960300, '0101000020E6100000E5D4CE30B525ECBF7616BD5301D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54686824754.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54686824754.webp', 'https://www.flickr.com/photos/zaragozaantigua/54686824754/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20948, 'Convento de San Josâ”œآ® 1808', '"Vista del convento de San Josâ”œآ® incendiado por los franceses". Serie Ruinas de Zaragoza, de Juan Gâ”œأ­lvez (dibujo) y Fernando Brambila (grabado), Câ”œأ­diz, 1812. Una de las mejores vistas del convento de San Josâ”œآ®, con el puente de acceso sobre el râ”œآ،o Huerva en primer plano, desde la actual calle Aznar Molina, en su tramo entre Asalto y Hâ”œأ­bitat Don 2000. Fuente: artillerosdearagon.blogspot.com', 1808, 1808, 1808, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64814200, -0.87251300, '0101000020E610000013B70A62A0EBEBBFFF942A51F6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15085319677.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15085319677.webp', 'https://www.flickr.com/photos/zaragozaantigua/15085319677/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20964, 'Puente de San Josâ”œآ® c.1818', '"El alguacil Lampiâ”œâ–’os cosido dentro de un caballo muerto", dibujo de Francisco de Goya. "En Zaragoza, a mediados del siglo pasado (XVIII), metieron a un alguacil llamado Lampiâ”œâ–’os en el cuerpo de un rocâ”œآ،n muerto y lo cosieron; toda la noche se mantuvo vivo", escribe Goya a pie de dibujo. Ya en 1725 el medianero Antonio Gavâ”œآ،n incluyâ”œâ”‚ esta tremenda historia en "El anti-papismo de un aragonâ”œآ®s anglicano en la Inglaterra del siglo XVIII". En esa obra, el alguacil se llamaba Guadalajara, y era guardia de la Universidad, en la plaza de la Magdalena, contratado para arrestar a los malos estudiantes. Era tan celoso en su desempeâ”œâ–’o, que se convirtiâ”œâ”‚ en azote de estudiantes, putas, y sospechosos en general, hasta que unos resentidos estudiantes decidieron darle un escarmiento a la zaragozana: lo secuestraron y sacaron de la ciudad por la Puerta Quemada y, junto al Puente de San Josâ”œآ® sobre el Huerva, lo metieron atado de pies y manos dentro de un caballo muerto, previamente destripado. Cosieron el cuerpo del caballo con la cabeza del pobre guardia fuera, por el orificio anal, y asâ”œآ، lo dejaron toda la noche, expuesto a las alimaâ”œâ–’as atraidas por el olor visceral. Sobreviviâ”œâ”‚ vociferando a los perros que se acercaban a merendarse los restos. El pasmo que produjo el espectâ”œأ­culo con las primeras luces del dâ”œآ،a siguiente (una humana testa en el culo de un caballo), derivâ”œâ”‚ el asunto en cosa del demonio, y el caso fue llevado al Tribunal de la Santa Inquisiciâ”œâ”‚n, que procediâ”œâ”‚ a torturar al hombre-caballo para hallar la verdad, o que pereciera en el intento. Y la verdad se descubriâ”œâ”‚ cuando el potro de tortura desgarrâ”œâ”‚ los cosidos del caballo, y el alguacil se escurriâ”œâ”‚ lastimosamente al suelo. Tres semanas despuâ”œآ®s, el alguacil morâ”œآ،a de calenturas, perdonando a los traviesos estudiantes madaleneros, que le correspondieron componiâ”œآ®ndole una apropiada y sentida elegâ”œآ،a funeraria. En el dibujo, Goya se centra en la turbadora imagen del hombre-caballo defendiâ”œآ®ndose a gritos de unos asombrados perr', 1818, 1818, 1818, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64814200, -0.87251300, '0101000020E610000013B70A62A0EBEBBFFF942A51F6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16948854662.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16948854662.webp', 'https://www.flickr.com/photos/zaragozaantigua/16948854662/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20976, 'Convento de San Josâ”œآ® 1808', 'Apunte de Juan Gâ”œأ­lvez para un grabado de la colecciâ”œâ”‚n de "Ruinas de Zaragoza" (1812) que no se llegâ”œâ”‚ a realizar, y que sirviâ”œâ”‚ de base para la sâ”œآ، realizada "Vista del convento de San Josâ”œآ® incendiado por los franceses", de la misma serie, grabada por la mano de Fernando Brambila. El apunte incluye una precisa imagen del antiguo y barroco convento de San Josâ”œآ® de los Carmelitas Descalzos (destaca su imponente iglesia), el puente de San Josâ”œآ® sobre el râ”œآ،o Huerva, demolido parcialmente por los defensores de la ciudad, que tambiâ”œآ®n talaron los â”œأ­rboles de las riberas del râ”œآ،o y el entorno para una mejor visual. Fuente visual: Imagen aportada por Josâ”œآ® Luis Cintora a la obra de Rafael Contento Mâ”œأ­rquez, "Las Ruinas de Zaragoza de Gâ”œأ­lvez y Brambila. Una epopeya calcogrâ”œأ­fica", Zaragoza, IFC, 2010.', 1808, 1808, 1808, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64755000, -0.87221100, '0101000020E61000003FC4060B27E9EBBF2D431CEBE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20291995778.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20291995778.webp', 'https://www.flickr.com/photos/zaragozaantigua/20291995778/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20977, 'Convento de San Josâ”œآ® 1806', 'Convento de carmelitas descalzos de San Josâ”œآ®. Dibujo de Louis-Franâ”œآ؛ois Lejeune y grabado de Perdoux, 1806. Ademâ”œأ­s del convento, en el grabado aparecen el puente de San Josâ”œآ® sobre el râ”œآ،o Huerva, y un fragmento de la puerta Quemada a la izquierda. Fuente: Ensemble de 255 dessins originaux â”œأ­ la mine de plomb, â”œأ، la plume avec lavis ayant servi â”œأ، illustrer le Voyage pittoresque et historique de lأ”أ‡أ–Espagne, par Alexandre de Laborde (1773-1842).', 1806, 1806, 1806, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64814200, -0.87251300, '0101000020E610000013B70A62A0EBEBBFFF942A51F6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20357644581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20357644581.webp', 'https://www.flickr.com/photos/zaragozaantigua/20357644581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21101, 'Matadero c.1885', 'El nuevo macelo de la ciudad, diseâ”œâ–’ado por Ricardo Magdalena y realizado entre 1878-1875, es una obra funcional, apropiada y estâ”œآ®ticamente agradable, que cayâ”œâ”‚ como un paracaidista en la ubicaciâ”œâ”‚n prevista, en la calle de Miguel Servet en su confluencia con el arranque del camino de las Fuentes, entre huertos, solares, riegos, vides, torres, y campos de hortalizas. No podâ”œآ،a ser de otra forma, por razones higiâ”œآ®nico-sanitarias, dadas las caracterâ”œآ،sticas de los materiales que deberâ”œآ،a procesar. La imagen ha sido capturada casi desde el Camino de San Josâ”œآ®, donde aâ”œâ–’os despuâ”œآ®s, cuando la urbanizaciâ”œâ”‚n de la zona avance, se habilitarâ”œأ­ un "Callejâ”œâ”‚n del Pilar" para conectarlo con Miguel Servet. Mâ”œأ­s tarde serâ”œأ­ redenominado "Calle del Matadero". El frontal del matadero, con sus tres grandes naves confluyendo en el patio central donde la fuente del "Buen Pastor", y su monumental puerta de acceso, siguen siendo hoy en dâ”œآ،a, casi un siglo despuâ”œآ®s, un espectâ”œأ­culo pâ”œâ•‘blico y câ”œآ،vico de primer orden.', 1885, 1885, 1885, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64456800, -0.87038700, '0101000020E610000038A27BD635DAEBBF2906483481D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16099500504.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16099500504.webp', 'https://www.flickr.com/photos/zaragozaantigua/16099500504/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21251, 'Penal de San Josâ”œآ® 1907', 'Postal. "Colecciâ”œâ”‚n Patria y Fe nâ”œâ•‘m. 24, Zaragoza 1908 - Centenario de los Sitios", 1907. "Antiguo convento de Carmelitas Descalzos, y luego presidio de Zaragoza, situado mâ”œأ­s allâ”œأ­ de la puerta Quemada, al otro lado del Huerva, en un terreno elevado inmediato al râ”œآ،o. Fue constantemente atacado por ocho baterâ”œآ،as francesas. Los aragoneses lo incendiaron antes de abandonarlo y sobre sus ruinas instalâ”œأ­ronse baterâ”œآ،as que hicieron mucho daâ”œâ–’o a las tropas de Napoleâ”œâ”‚n." Con motivo del Centenario 1 de "Los Sitios", la Imprenta Casaâ”œâ–’al realiza en 1907 la colecciâ”œâ”‚n de postales "Patria y Fe", y en ella incluye imâ”œأ­genes de algunos de los escenarios considerados referenciales de ese evento. Asâ”œآ،, con el nâ”¬â•‘ 24 de la serie, una imagen recoge el estado del "Antiguo Penal de San Josâ”œآ®", antiguo Convento de S. Josâ”œآ® de los Carmelitas Descalzos, arruinado durante el conflicto de 1808-09, y reconstruido luego. Fue Penal Correccional hasta 1900, y estuvo abandonado unos aâ”œâ–’os, hasta que fue adjudicado al Ejâ”œآ®rcito de Tierra para uso como Cuartel de Intendencia. La imagen se ha capturado desde el puente de San Josâ”œآ®, y en ella se ve uno de los torreoncillos construidos como garitas de vigilancia de presos, en sus tiempos de Penal. A la vista de otras imâ”œأ­genes del entorno, la foto estâ”œأ­ reproducida horizontalmente al revâ”œآ®s. Fuente visual y del texto de la postal: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'SAN JOSâ”œأ«', 41.64755000, -0.87221100, '0101000020E61000003FC4060B27E9EBBF2D431CEBE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20322375321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20322375321.webp', 'https://www.flickr.com/photos/zaragozaantigua/20322375321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21788, 'Camino de San Josâ”œآ® c.1938', 'Imagen de uno de los autobuses en servicio en la lâ”œآ،nea "Barrio de San Josâ”œآ®" a finales de los aâ”œâ–’os 30, integrante de la compaâ”œâ–’â”œآ،a "Autobuses Ensanches Zaragoza" del empresario del sector Jesâ”œâ•‘s Sâ”œأ­nchez Falces.', 1938, 1938, 1938, 'Anos 30', 'SAN JOSâ”œأ«', 41.64399100, -0.87294100, '0101000020E610000018CDCAF621EFEBBF8CF50D4C6ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23866038221.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23866038221.webp', 'https://www.flickr.com/photos/zaragozaantigua/23866038221/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21801, 'Miguel Servet 1933', 'Imagen capturada en un arbolado tramo de la calle de Miguel Servet en el antiguo barrio de Montemolâ”œآ،n, posiblemente entre el Matadero, la calle de las Escuelas y la de Utrillas, muy cerca del arranque del camino de Cabaldâ”œâ”‚s y el Frontâ”œâ”‚n Zaragozano (a la derecha, fuera de plano). Al fondo, traquetea una unidad tranviaria de la lâ”œآ،nea 1 Bajo Aragâ”œâ”‚n. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'SAN JOSâ”œأ«', 41.64387200, -0.86961300, '0101000020E610000076A565A4DED3EBBFB267CF656AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26311030859.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26311030859.webp', 'https://www.flickr.com/photos/zaragozaantigua/26311030859/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21866, 'C.â”¬â•‘ de San Josâ”œآ® 1933', 'Imagen de la fachada de los enormes talleres de muebles del establecimiento La Catedral del Mueble de Urbano Bernardos, sitos en el camino de San Josâ”œآ® nâ”¬â•‘ 32, esquineros con la calle de Miraflores (a la derecha, fuera de plano). Con una experiencia de treinta aâ”œâ–’os en el oficio, aquâ”œآ، se construâ”œآ،an selectos muebles en estilo y materiales nobles, ademâ”œأ­s de muebles econâ”œâ”‚micos y accesibles para casi todos los bolsillos (eso al menos sugerâ”œآ،a la publicidad). En el arranque de la câ”œآ®ntrica calle de Santiago contaba con un extenso y concurrido local expositor y de venta. En la imagen, la fachada de los talleres recayente al camino de San Josâ”œآ®, con los â”œأ­rboles que lo jalonaban hasta que fueron cortados al principio de la dâ”œآ®cada de los aâ”œâ–’os cuarenta, cuando el tendido de la nueva lâ”œآ،nea tranviaria "San Josâ”œآ®". Este notable edificio perdurâ”œâ”‚ hasta su derribo y sustituciâ”œâ”‚n por modernos bloques de viviendas, no ha mucho. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'SAN JOSâ”œأ«', 41.64402300, -0.87283300, '0101000020E610000080D3BB783FEEEBBF976F7D586FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36420672135.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36420672135.webp', 'https://www.flickr.com/photos/zaragozaantigua/36420672135/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21918, 'Calle de Miguel Servet 1934', 'Posado de un teniente de la Comandancia de Intendencia de Zaragoza montado en moto con sidecar ante la fachada que da ingreso al Matadero municipal desde la calle de Miguel Servet. Competan la escena, tras â”œآ®l, tropas armadas, grupo de civiles y niâ”œâ–’os.', 1934, 1934, 1934, 'Anos 30', 'SAN JOSâ”œأ«', 41.64458400, -0.87037600, '0101000020E61000003E25E7C41EDAEBBF2FC37FBA81D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54169474966.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54169474966.webp', 'https://www.flickr.com/photos/zaragozaantigua/54169474966/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22344, 'Galletas Polen 1968', 'Imagen de la Fabrica de Galletas Polen, sita en la esquina de las calles del Fuero del Trabajo (nâ”¬â•‘ 4, a la izquierda), y la Avenida de San Josâ”œآ® (nâ”¬â•‘ 38, a la derecha), donde estaba el despacho o tienda, los aromas de este establecimiento perfumaron esta parte del Barrio de San Josâ”œآ® durante unas cuantas dâ”œآ®cadas, hasta que se trasladaron al polâ”œآ،gono de Cogullada. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”œأ«', 41.64336500, -0.87300500, '0101000020E6100000C8D2872EA8EFEBBF0E32C9C859D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20230845931.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20230845931.webp', 'https://www.flickr.com/photos/zaragozaantigua/20230845931/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22345, 'Avenida de San Josâ”œآ® 1969', 'Imagen de la avenida de San Josâ”œآ®. A la izquierda, tras la pausa publicitaria, el pabellâ”œâ”‚n de Hermanas Enfermas del antiguo Asilo de Pobres. A continuaciâ”œâ”‚n, tras la calle Miraflores, la que fuera fâ”œأ­brica de muebles Abenia. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1969, 1969, 1969, 'Anos 60', 'SAN JOSâ”œأ«', 41.64439100, -0.87290800, '0101000020E61000002A560DC2DCEEEBBF1A6B7F677BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20233029718.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20233029718.webp', 'https://www.flickr.com/photos/zaragozaantigua/20233029718/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22544, 'Matadero Municipal 1971', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 05/02/1971. El arquitecto municipal Ricardo Magdalena proyectâ”œâ”‚ un nuevo matadero municipal, que fue terminado en 1884 en la antigua huerta de Montemolâ”œآ،n. Inaugurado como recinto de la Exposiciâ”œâ”‚n Aragonesa de productos industriales de 1885-1886, entrâ”œâ”‚ en funcionamiento como matadero efectivo al aâ”œâ–’o siguiente. Los sacrificios de animales cesaron en 1980, y el matadero cerrâ”œâ”‚ definitivamente en 1981. En la imagen, el patio del Matadero, lleno de viejos, pero activos, camiones de reparto, junto a uno nuevo.', 1971, 1971, 1971, 'Anos 70', 'SAN JOSâ”œأ«', 41.64477600, -0.87006000, '0101000020E61000002BD9B11188D7EBBF739F1C0588D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14945573365.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14945573365.webp', 'https://www.flickr.com/photos/zaragozaantigua/14945573365/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22618, 'Cuartel de San Josâ”œآ® 1973', 'Foto Monge, 1973. Esta especie de globo instalado en el mismo lugar donde hasta poco antes hubo "otra singular edificaciâ”œâ”‚n destinada a la exhibiciâ”œâ”‚n del Cinerama", albergâ”œâ”‚ la sala de actos de los Cristianos Adventistas del Sâ”œآ®ptimo Dâ”œآ،a. Obra del arquitecto vallisoletado Josâ”œآ® Miguel de Prada Poole, se hinchaba en 20 minutos y tenâ”œآ،a un aforo de 400 personas. Mientras, al fondo, se termina de construir el edificio denominado "Hâ”œأ­bitat Don 2000", que sigue presidiendo las vistas de la ciudad desde varios kilâ”œâ”‚metros a la redonda. A la izquierda, pequeâ”œâ–’o fragmento del edificio de Elâ”œآ®ctricas Reunidas de Zaragoza. Posteriormente, por estos terrenos del antiguo Cuartel de San Josâ”œآ® se prolongâ”œâ”‚ el camino de las Torres hasta el puente de Las Fuentes. Fuente: Diario Amanecer, 24 de enero de 1973.', 1973, 1973, 1973, 'Anos 70', 'SAN JOSâ”œأ«', 41.64770600, -0.87135900, '0101000020E6100000906802452CE2EBBF24B6BB07E8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19367279556.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19367279556.webp', 'https://www.flickr.com/photos/zaragozaantigua/19367279556/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22628, 'Miguel Servet 1974', 'Tranvâ”œآ،a nâ”¬â•‘ 226 de la lâ”œآ،nea 11 (Parque-San Josâ”œآ®) terminando de dar la curva que desde la Avenida de San Josâ”œآ® lo situaba en Miguel Servet, en direcciâ”œâ”‚n Parque. A su derecha, otra unidad de esta lâ”œآ،nea se dirige hacia San Josâ”œآ®. Entre adoquines, en el suelo, el cruce de vâ”œآ،as de las lâ”œآ،neas 11 y la 1 "Bajo Aragâ”œâ”‚n". La gran publicidad de "Residencial Paraâ”œآ،so", anuncia la importante mudanza que se estaba produciendo en la apetitosa y gran pastilla situada entre los paseos de Las Damas y de Mola. El edificio que soporta la publicidad tambiâ”œآ®n serâ”œأ­ luego mudado por otro mâ”œأ­s nuevo.', 1974, 1974, 1974, 'Anos 70', 'SAN JOSâ”œأ«', 41.64613900, -0.87195200, '0101000020E61000003DD175E107E7EBBFC7D5C8AEB4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20152158770.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20152158770.webp', 'https://www.flickr.com/photos/zaragozaantigua/20152158770/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22632, 'Frontâ”œâ”‚n Zaragozano 1975', 'Restos del "Frontâ”œâ”‚n Zaragozano", construido a finales del s. XIX cerca del Camino del Bajo Aragâ”œâ”‚n y el nuevo Macelo. En 1967 fue derribado (casi a la vez que el "Frontâ”œâ”‚n Aragonâ”œآ®s"), para urbanizar la zona y comenzar a construir nuevos bloques de viviendas del barrio de San Josâ”œآ®. En la imagen, reliquia de la puerta de acceso al "Frontâ”œâ”‚n Zaragozano de Pelota", en ladrillo y formas neomudâ”œآ®jares. Acorralada entre nuevas y enormes colmenas habitacionales (los bloques de la imagen, recayentes a Monasterio de Poblet), esta pequeâ”œâ–’a puerta de acceso no tuvo espacio para ser preservada, y su memoria, que era parte de la reciente memoria de la ciudad, fue borrada.', 1975, 1975, 1975, 'Anos 70', 'SAN JOSâ”œأ«', 41.64391800, -0.87039800, '0101000020E6100000321F10E84CDAEBBF22A7AFE76BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20228987961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20228987961.webp', 'https://www.flickr.com/photos/zaragozaantigua/20228987961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22651, 'La Salle Montemolâ”œآ،n 1970', 'Posado en el patio del colegio La Salle Montemolâ”œآ،n, levantado en el antiguo camino de las Torres con proyecto de 1915 de Francisco Albiâ”œâ–’ana, junto a la Fundiciâ”œâ”‚n de Iranzo de la calle Miguel Servet (derecha). Este enorme espacio, dos aâ”œâ–’os mâ”œأ­s tarde, serâ”œأ­ vendido, el colegio derribado, y el solar reutilizado para la construcciâ”œâ”‚n de un enorme megabloque de viviendas. Los Hermanos de las Escuelas Cristianas abrirâ”œأ­n entonces un nuevo centro en la calle Josâ”œآ® Galiay.', 1970, 1970, 1970, 'Anos 70', 'SAN JOSâ”œأ«', 41.64714000, -0.87386400, '0101000020E610000016DBA4A2B1F6EBBF7BF7C77BD5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21187990435.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21187990435.webp', 'https://www.flickr.com/photos/zaragozaantigua/21187990435/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22768, 'Miguel Servet 1971', 'Puerta de ingreso del matadero municipal en la calle de Miguel Servet 55, en el momento en que sale uno de los veteranos camiones de reparto. Este macelo, obra del arquitecto Ricardo Magdalena, entrâ”œâ”‚ en funcionamiento en 1887 y fue cerrado como tal en 1981, para albergar despuâ”œآ®s otros servicios pâ”œâ•‘blicos del Ayuntamiento. Sobre el firme, el tendido, y aâ”œآ®reo, el cableado que por la derecha conducâ”œآ،a a las cocheras de los tranvâ”œآ،as.', 1971, 1971, 1971, 'Anos 70', 'SAN JOSâ”œأ«', 41.64453300, -0.87025000, '0101000020E61000000C022B8716D9EBBFAD18AE0E80D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33438717146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33438717146.webp', 'https://www.flickr.com/photos/zaragozaantigua/33438717146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22782, 'Av. de San Josâ”œآ® 1979', 'Imagen capturada en la avenida de San Josâ”œآ® y centrada en el decimonâ”œâ”‚nico y desaparecido (por derribo) pabellâ”œâ”‚n sanatorio de las Hermanitas Enfermas integrante del gran complejo asistencial de la Congregaciâ”œâ”‚n de las Hermanitas de los Ancianos Desamparados. A la izquierda, fuera de plano, el principio de la calle de Miraflores. Fuente visual: AMZ.', 1979, 1979, 1979, 'Anos 70', 'SAN JOSâ”œأ«', 41.64439100, -0.87290800, '0101000020E61000002A560DC2DCEEEBBF1A6B7F677BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37884084724.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37884084724.webp', 'https://www.flickr.com/photos/zaragozaantigua/37884084724/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22838, 'Calle Monasterio de Samos aâ”œâ–’os 80', 'Aâ”œâ–’os 80 del siglo XX. La calle Monasterio de Samos, en su tramo entre Compromiso de Caspe y Miguel Servet, fue abierta en los aâ”œâ–’os 70, restâ”œأ­ndole terreno al perâ”œآ،metro del antiguo Matadero Municipal, hoy Centro Câ”œآ،vico Salvador Allende. En la foto, con los edificios de Miguel Servet al fondo, vemos unas construcciones naranjas abajo a la derecha, que luego serâ”œآ،an derruidas para edificar una comisarâ”œآ،a agresora del conjunto, que hoy es un centro administrativo municipal. Foto: Santos Santos.', 1980, 1980, 1989, 'Anos 80', 'SAN JOSâ”œأ«', 41.64529100, -0.87055600, '0101000020E61000003BC5AA4198DBEBBF9AB33EE598D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14868808299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14868808299.webp', 'https://www.flickr.com/photos/zaragozaantigua/14868808299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22928, 'Miguel Servet 1981', 'Foto: Javier Peâ”œâ–’a. Calle de Miguel Servet, vista desde la esquina con la avenida del Compromiso de Caspe (derecha, fuera de encuadre). Al fondo, confluencia con el camino de las Torres. Fuente: www.facebook.com/photo.php?fbid=1519294098086430&set=...', 1981, 1981, 1981, 'Anos 80', 'SAN JOSâ”œأ«', 41.64653700, -0.87262100, '0101000020E6100000ABB019E082ECEBBFB55373B9C1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30683583891.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30683583891.webp', 'https://www.flickr.com/photos/zaragozaantigua/30683583891/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22962, 'C.â”¬â•‘ de las Torres 1985', 'Canicular imagen capturada en el camino de las Torres a la altura del inmueble del nâ”¬â•‘ 9, y centrada en el aparentemente anodino gran solar tapiado y esquinero con la calle de Amado Nervo, que en el centro de la escena muestra su desemboque en el camino. Esta calle de Amado Nervo fue asâ”œآ، denominada en 1965 como homenaje al poeta modernista mejicano Amado Ruiz Nervo Ordaz, y entonces comenzaba en la paralela calle de la Reina Fabiola y terminaba en fondo de saco ante el perâ”œآ،metro de la fâ”œأ­brica de harinas de San Josâ”œآ® aquâ”œآ، establecida desde dâ”œآ®cadas antes, lo que determinâ”œâ”‚ el urbanismo de la zona hasta su derribo a principios de los aâ”œâ–’os 80 del pasado siglo XX. El solar de la imagen perduraba como recuerdo de su ubicaciâ”œâ”‚n, una vez retranqueada buena parte de su superficie que se extendâ”œآ،a por casi toda la anchura del actual camino de las Torres, casi hasta la desembocadura de la calle de la Concepciâ”œâ”‚n. Aâ”œâ–’os mâ”œأ­s tarde en el solar de la imagen se construirâ”œآ،a el actual bloque de viviendas del nâ”¬â•‘ 11 del camino, denominado "Edificio Alejandrâ”œآ،a", que casualmente parece hacer referencia al verso alejandrino utilizado de forma caracterâ”œآ،stica por poetas modernistas hispanoamericanos como Rubâ”œآ®n Darâ”œآ،o y Amado Nervo.', 1985, 1985, 1985, 'Anos 80', 'SAN JOSâ”œأ«', 41.64631600, -0.87393800, '0101000020E6100000A96917D34CF7EBBFD670917BBAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53257348800.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53257348800.webp', 'https://www.flickr.com/photos/zaragozaantigua/53257348800/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23137, 'Miguel Servet 2000', 'Imagen centrada en la chaflanera esquina, o despartidero, que indica, hacia la derecha, el arranque de la avenida de San Josâ”œآ®, mientras que hacia la izquierda prosigue la calle de Miguel Servet. Un inmenso telâ”œâ”‚n de fondo, patrocinado por una marca de alcohol escocâ”œآ®s (propiedad de una conocida compaâ”œâ–’â”œآ،a ronera), hace de pantalla publicitaria para los humanos que por allâ”œآ، transiten, mientras del otro lado se remodela el edificio del nâ”¬â•‘ 56 de Miguel Servet. Justo a su izquierda, una de las â”œâ•‘ltimas imagenes de la antigua casa del nâ”¬â•‘ 58 de esa calle, que poco tiempo despuâ”œآ®s serâ”œآ،a derribada y homologada con un entorno mâ”œأ­s moderno, y vertical. A la derecha, entre colosos, el antiguo nâ”¬â•‘ 9 de la avenida de San Josâ”œآ® ya ha sido derribado, y estâ”œأ­ encaminado hacia la hipernormalizaciâ”œâ”‚n.', 2000, 2000, 2000, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.64594900, -0.87207000, '0101000020E6100000B9533A58FFE7EBBF24F1F274AED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31818947400.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31818947400.webp', 'https://www.flickr.com/photos/zaragozaantigua/31818947400/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23222, 'Calle de Miguel Servet 2014', 'Manifestaciâ”œâ”‚n antifascista el 20 de noviembre de 2014, a su paso por la calle de Miguel Servet, con el cruce con la avenida del Compromiso de Caspe al fondo. La pancarta, de la Federaciâ”œâ”‚n de Asociaciones de Barrios de Zaragoza.', 2014, 2014, 2014, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.64639300, -0.87242600, '0101000020E610000059C345EEE9EAEBBF82AE7D01BDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51140224272.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51140224272.webp', 'https://www.flickr.com/photos/zaragozaantigua/51140224272/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23249, 'C.â”¬â•‘ de Las Fuentes aâ”œâ–’os 20', 'Imagen del camino de Las Fuentes y acequia Mayor, desde Miguel Servet. A la izquierda, taller de caldererâ”œآ،a de Josâ”œآ® Claver. Las inmediatas vâ”œآ،as del tranvâ”œآ،a en el suelo apuntan hacia Miguel Servet, a la derecha. Tras la chimenea del transformador elâ”œآ®ctrico, la acequia de San Josâ”œآ® (que viene por Miguel Servet del Camino de las Torres) y la doble hilera de â”œأ­rboles, marcan el arranque del camino de las Fuentes. A la izquierda, las parcelas con los nâ”œâ•‘meros 64, 64 duplicado, y 64 triplicado. A la derecha, las traseras del nâ”œâ•‘mero 27 de Miguel Servet. Esto en la actualidad es el comienzo de Compromiso de Caspe, quedando a la derecha el bloque de viviendas nâ”¬â•‘ 1, y a la izquierda, el bloque de viviendas nâ”¬â•‘ 3. Fuente visual: foto Jesâ”œâ•‘s Cormâ”œأ­n, en "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1920, 1920, 1929, 'Anos 20', 'SAN JOSâ”œأ«', 41.64613900, -0.87195200, '0101000020E61000003DD175E107E7EBBFC7D5C8AEB4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14921981846.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14921981846.webp', 'https://www.flickr.com/photos/zaragozaantigua/14921981846/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23254, 'Huerva 1920', 'Una captura titulada oficialmente "Panorâ”œأ­mica de un complejo industrial junto a un canal y una zona arbolada. En primer plano, un hombre se aproxima al objetivo del fotâ”œâ”‚grafo". Vista del râ”œآ،o Huerva aguas abajo del puente de san Josâ”œآ®, en una imagen capturada desde el pronunciado talud de la calle del Asalto con el telâ”œâ”‚n de fondo del cuartel de la tercera comandancia de Intendencia. En el centro de la escena, canal que deriva agua del râ”œآ،o hacia la central transformadora de ERZ, y entre los â”œأ­rboles que delimitan el Corral de abastos de Intendencia se destaca la chimenea de la fâ”œأ­brica de regaliz situada inmediatamente detrâ”œأ­s. A la derecha y sobre los â”œأ­rboles, edificios de la harinera del Pilar. Fuente visual: Gabriel Faci Abad, en AHPZ.', 1920, 1920, 1920, 'Anos 20', 'SAN JOSâ”œأ«', 41.64755000, -0.87221100, '0101000020E61000003FC4060B27E9EBBF2D431CEBE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20355412881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20355412881.webp', 'https://www.flickr.com/photos/zaragozaantigua/20355412881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
